 27	import { CubesIcon, StorageDomainIcon } from '@patternfly/react-icons';
 28	
 29	const getPageTitle = (path: string, t: TFunction) => {
 30	  if (path.includes(StartingPoint.STORAGE_CLUSTER)) {
 31	    return t('Storage cluster');
 32	  }
 33	  if (path.includes(StartingPoint.OBJECT_STORAGE)) {
 34	    return t('Object storage');
 35	  }
 36	  if (path.includes(StartingPoint.EXTERNAL_SYSTEMS)) {
 37	    return t('External systems');
 38	  }
 39	  if (path.includes(StartingPoint.OVERVIEW)) {
 40	    return t('Overview');
 41	  }
 42	  return t('Storage cluster');
 43	};
 44	
 45	const EmptyStateBodyObjectPage: React.FC = () => {
 46	  const { t } = useCustomTranslation();
 47	  return (
 48	    <Trans t={t}>
 49	      To access Object Storage, you can either configure the storage
 50	      cluster(provider block, file and object) or deploy MCG only(for Object
 51	      storage without block and file)
 52	    </Trans>
 53	  );
 54	};
