 56	const EmptyStateBodyStorageClusterPage: React.FC = () => {
 57	  const { t } = useCustomTranslation();
 58	  return (
 59	    <Trans t={t}>
 60	      Provision a storage cluster using local devices on your OpenShift nodes.
 61	      Data Foundation with block, shared filesystem and object services
 62	    </Trans>
 63	  );
 64	};
 65	
 66	const EmptyStateBodyOverviewPage: React.FC = () => {
 67	  const { t } = useCustomTranslation();
 68	  return (
 69	    <Trans t={t}>
 70	      Start configuring your storage platform to unlock core Data Foundation
 71	      features.
 72	    </Trans>
 73	  );
 74	};
 75	
 76	const EmptyStateBodyExternalSystemPage: React.FC = () => {
 77	  const { t } = useCustomTranslation();
 78	  return (
 79	    <Trans t={t}>
 80	      Connect an external storage system to get started. Add{' '}
 81	      <span className="pf-v6-u-font-weight-bold">
 82	        IBM FlashSystem, IBM Scale or Red Hat Ceph Storage{' '}
 83	      </span>{' '}
 84	      to begin managing it.
 85	    </Trans>
 86	  );
 87	};
 88	
 89	const EmptyStatePageBody: React.FC = () => {
 90	  const location = useLocation();
 91	  const startingPoint = getModalStartPoint(location.pathname);
 92	  switch (startingPoint) {
 93	    case StartingPoint.OVERVIEW:
 94	      return <EmptyStateBodyOverviewPage />;
 95	    case StartingPoint.STORAGE_CLUSTER:
 96	      return <EmptyStateBodyStorageClusterPage />;
 97	    case StartingPoint.OBJECT_STORAGE:
 98	      return <EmptyStateBodyObjectPage />;
 99	    case StartingPoint.EXTERNAL_SYSTEMS:
100	      return <EmptyStateBodyExternalSystemPage />;
101	    default:
102	      return <EmptyStateBodyOverviewPage />;
103	  }
104	};
105	
