107	  const { t } = useCustomTranslation();
108	  const launchModal = useModal();
109	  return (
110	    <EmptyState>
111	      <EmptyStateHeader
112	        titleText={t('No external systems connected')}
113	        headingLevel="h4"
114	        icon={<EmptyStateIcon icon={CubesIcon} />}
115	      />
116	      <EmptyStateBody>
117	        <EmptyStatePageBody />
118	      </EmptyStateBody>
119	      <EmptyStateFooter>
120	        <EmptyStateActions>
121	          <Button
122	            data-test="configure-external-systems"
123	            variant={ButtonVariant.primary}
124	            onClick={() => {
125	              launchModal(ExternalSystemsSelectModal, {});
126	            }}
127	          >
128	            {t('Connect external systems')}
129	          </Button>
130	        </EmptyStateActions>
131	        <EmptyStateActions>
132	          <ViewDocumentation
133	            doclink={externalSystemsDoc(DOC_VERSION)}
134	            text={t('Explore all supported external systems')}
135	          />
136	        </EmptyStateActions>
137	      </EmptyStateFooter>
138	    </EmptyState>
139	  );
140	};
141	const InitialEmptyStatePage: React.FC = () => {
142	  const { t } = useCustomTranslation();
143	  const location = useLocation();
144	  const path = location.pathname;
145	  const title = getPageTitle(path, t);
146	  const launchModal = useModal();
147	  const isExternalSystems = path.includes(StartingPoint.EXTERNAL_SYSTEMS);
148	
149	  return (
150	    <>
151	      <Helmet>
152	        <title>{title}</title>
153	      </Helmet>
154	      <PageHeading title={title} />
155	      {!!isExternalSystems ? (
156	        <ExternalSystemsEmptyState />
157	      ) : (
158	        <EmptyState>
159	          <EmptyStateHeader
160	            titleText={t('Storage cluster is not configured')}
161	            headingLevel="h4"
162	            icon={<EmptyStateIcon icon={StorageDomainIcon} />}
163	          />
164	          <EmptyStateBody>
165	            <EmptyStatePageBody />
166	          </EmptyStateBody>
167	          <EmptyStateFooter>
168	            <EmptyStateActions>
169	              <Button
170	                data-test="configure-data-foundation"
171	                variant={ButtonVariant.primary}
172	                onClick={() => {
173	                  launchModal(StorageClusterCreateModal, {});
174	                }}
175	              >
176	                {t('Configure Data Foundation')}
177	              </Button>
178	            </EmptyStateActions>
179	            <EmptyStateActions>
180	              <Button
181	                variant={ButtonVariant.link}
182	                onClick={() => {
183	                  return null;
184	                }}
185	              >
186	                {t('Documentation link')}
187	              </Button>
188	            </EmptyStateActions>
189	          </EmptyStateFooter>
190	        </EmptyState>
191	      )}
192	    </>
193	  );
194	};
195	
196	export default InitialEmptyStatePage;

